import {
  Injectable,
  NotFoundException,
  UnauthorizedException,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import * as bcrypt from 'bcrypt';
import { UserEntity } from '../../database/entities/user.entity';
import { RefreshTokenEntity } from '../../database/entities/refresh-token.entity';
import { PermissionEntity } from '../../database/entities/permission.entity';
import { RolePermissionEntity } from '../../database/entities/role-permission.entity';
import { JwtPayload } from './strategies/jwt.strategy';

const BCRYPT_ROUNDS = 10;

@Injectable()
export class AuthService {
  constructor(
    @InjectRepository(UserEntity)
    private readonly userRepo: Repository<UserEntity>,

    @InjectRepository(RefreshTokenEntity)
    private readonly refreshTokenRepo: Repository<RefreshTokenEntity>,

    private readonly jwtService: JwtService,
  ) {}

  // ─── Login ───────────────────────────────────────────────────────────────────

  async login(
    email: string,
    password: string,
  ): Promise<{ access_token: string; refresh_token: string }> {
    const user = await this.userRepo.findOne({
      where: { email, isActive: true },
    });

    if (!user) {
      throw new UnauthorizedException('Invalid credentials');
    }

    const isPasswordValid = await bcrypt.compare(password, user.passwordHash);
    if (!isPasswordValid) {
      throw new UnauthorizedException('Invalid credentials');
    }

    // Update last login timestamp
    await this.userRepo.update(user.id, { lastLoginAt: new Date() });

    const accessToken = this.issueAccessToken(user);
    const refreshToken = await this.issueRefreshToken(user.id);

    return { access_token: accessToken, refresh_token: refreshToken };
  }

  // ─── Refresh Token ────────────────────────────────────────────────────────────

  async refreshToken(token: string): Promise<{ access_token: string }> {
    // Find all non-revoked tokens for the user and validate
    const tokenRecord = await this.findValidRefreshToken(token);

    const user = await this.userRepo.findOne({
      where: { id: tokenRecord.userId, isActive: true },
    });

    if (!user) {
      throw new UnauthorizedException('User not found or inactive');
    }

    const accessToken = this.issueAccessToken(user);
    return { access_token: accessToken };
  }

  // ─── Logout ───────────────────────────────────────────────────────────────────

  async logout(userId: string, token: string): Promise<void> {
    const tokenRecord = await this.findValidRefreshToken(token, userId);
    await this.refreshTokenRepo.update(tokenRecord.id, { isRevoked: true });
  }

  // ─── Get Current User ─────────────────────────────────────────────────────────

  async getMe(userId: string): Promise<Omit<UserEntity, 'passwordHash'> & { permissions: string[] }> {
    const user = await this.userRepo.findOne({
      where: { id: userId },
      relations: { role: true },
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    let permissions: string[] = [];
    if (user.role) {
      if (user.role.name.toLowerCase() === 'admin') {
        const allPermissions = await this.refreshTokenRepo.manager.find(PermissionEntity);
        permissions = allPermissions.map((p) => p.key);
      } else {
        const rolePermissions = await this.refreshTokenRepo.manager.find(RolePermissionEntity, {
          where: { roleId: user.role.id },
          relations: { permission: true },
        });
        permissions = rolePermissions
          .filter((rp) => rp.permission)
          .map((rp) => rp.permission.key);
      }
    }

    // Strip password hash before returning

    const { passwordHash, ...safeUser } = user;
    return {
      ...(safeUser as Omit<UserEntity, 'passwordHash'>),
      permissions,
    };
  }

  // ─── Internal Helpers ─────────────────────────────────────────────────────────

  private issueAccessToken(user: UserEntity): string {
    const payload: JwtPayload = {
      sub: user.id,
      email: user.email,
      roleId: user.roleId ?? null,
    };
    return this.jwtService.sign(payload);
  }

  private async issueRefreshToken(userId: string): Promise<string> {
    const rawToken = this.generateSecureToken();
    const tokenHash = await bcrypt.hash(rawToken, BCRYPT_ROUNDS);

    const expiresAt = new Date();
    expiresAt.setDate(expiresAt.getDate() + 7); // 7 days

    await this.refreshTokenRepo.save({
      userId,
      tokenHash,
      expiresAt,
      isRevoked: false,
    });

    return rawToken;
  }

  /**
   * Finds a non-revoked, non-expired refresh token record and validates the
   * raw token against the stored hash.
   */
  private async findValidRefreshToken(
    rawToken: string,
    userId?: string,
  ): Promise<RefreshTokenEntity> {
    const query = this.refreshTokenRepo
      .createQueryBuilder('rt')
      .where('rt.is_revoked = false')
      .andWhere('rt.expires_at > :now', { now: new Date() });

    if (userId) {
      query.andWhere('rt.user_id = :userId', { userId });
    }

    const candidates = await query.getMany();

    for (const record of candidates) {
      const matches = await bcrypt.compare(rawToken, record.tokenHash);
      if (matches) return record;
    }

    throw new UnauthorizedException('Invalid or expired refresh token');
  }

  private generateSecureToken(): string {
    const array = new Uint8Array(48);
    crypto.getRandomValues(array);
    return Buffer.from(array).toString('base64url');
  }
}

import { Injectable, Logger, OnModuleInit, OnModuleDestroy } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { Subject, Subscription } from 'rxjs';
import { concatMap } from 'rxjs/operators';
import { InventoryEntity } from '../../database/entities/inventory.entity';
import { ProductVariantEntity } from '../../database/entities/product-variant.entity';
import { MarketplaceProductEntity, SyncStatus } from '../../database/entities/marketplace-product.entity';
import { MarketplaceAccountEntity } from '../../database/entities/marketplace-account.entity';
import { EncryptionService } from '../marketplace/encryption.service';

interface InventorySyncJob {
  variantId: string;
  retryCount: number;
}

@Injectable()
export class InventorySyncQueueService implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(InventorySyncQueueService.name);
  private readonly queue$ = new Subject<InventorySyncJob>();
  private subscription: Subscription | null = null;
  private readonly maxRetries = 3;

  constructor(
    @InjectRepository(InventoryEntity)
    private readonly inventoryRepo: Repository<InventoryEntity>,
    @InjectRepository(ProductVariantEntity)
    private readonly variantRepo: Repository<ProductVariantEntity>,
    @InjectRepository(MarketplaceProductEntity)
    private readonly mappingRepo: Repository<MarketplaceProductEntity>,
    @InjectRepository(MarketplaceAccountEntity)
    private readonly accountRepo: Repository<MarketplaceAccountEntity>,
    private readonly encryption: EncryptionService,
  ) {}

  onModuleInit() {
    this.logger.log('Initializing Inventory Async Sync Queue Processor...');

    // Process stock updates sequentially to prevent marketplace race conditions or API lockups
    this.subscription = this.queue$
      .pipe(
        concatMap(async (job) => {
          try {
            const success = await this.syncInventoryToMarketplaces(job.variantId);
            if (!success && job.retryCount < this.maxRetries) {
              this.retryJob(job);
            }
          } catch (err: any) {
            this.logger.error(`Exception inside inventory queue processing: ${err.message}`);
            if (job.retryCount < this.maxRetries) {
              this.retryJob(job);
            }
          }
        })
      )
      .subscribe();
  }

  onModuleDestroy() {
    if (this.subscription) {
      this.subscription.unsubscribe();
      this.logger.log('Inventory Sync Queue Processor successfully stopped.');
    }
  }

  /**
   * Enqueues an inventory variant to be synchronized to external channels.
   */
  addSyncJob(variantId: string) {
    this.logger.log(`Enqueueing inventory sync job for variant ${variantId}`);
    this.queue$.next({
      variantId,
      retryCount: 0,
    });
  }

  /**
   * Performs the synchronization of variant stock to all mapped marketplace accounts.
   */
  private async syncInventoryToMarketplaces(variantId: string): Promise<boolean> {
    const variant = await this.variantRepo.findOne({
      where: { id: variantId },
    });

    if (!variant) {
      this.logger.error(`Inventory sync failed: Variant ${variantId} not found`);
      return false;
    }

    // 1. Calculate aggregated active available inventory for this variant across all warehouses
    const inventories = await this.inventoryRepo.find({
      where: { variantId },
      relations: { warehouse: true },
    });

    const activeInventories = inventories.filter((inv) => inv.warehouse && inv.warehouse.isActive);
    const totalAvailable = activeInventories.reduce((sum, inv) => sum + inv.available, 0);

    // 2. Discover all external marketplace mapping linkages for this variant's master product
    const mappings = await this.mappingRepo.find({
      where: { productId: variant.productId },
    });

    if (mappings.length === 0) {
      this.logger.log(`Inventory sync skipped: Variant "${variant.variantSku}" has no active marketplace SKU links.`);
      return true;
    }

    let overallSuccess = true;

    for (const mapping of mappings) {
      const account = await this.accountRepo.findOne({
        where: { id: mapping.marketplaceAccountId },
      });

      if (!account) {
        this.logger.warn(`Could not sync mapping ${mapping.id}: Account ${mapping.marketplaceAccountId} not found.`);
        overallSuccess = false;
        continue;
      }

      try {
        const isMockAccount = account.accessToken.includes('mock-') || account.sellerId.includes('_seller_');

        if (isMockAccount) {
          // Simulation mode Console Dump
          this.logger.log(`[SIMULATION LOG] Syncing inventory level to ${account.marketplace.toUpperCase()} store "${account.sellerName}":`);
          this.logger.log({
            action: 'sync_inventory',
            remoteProductId: mapping.marketplaceProductId,
            remoteVariantId: mapping.marketplaceVariantId || 'master_default',
            sku: variant.variantSku,
            newStock: totalAvailable,
            timestamp: new Date().toISOString(),
          });

          await new Promise((resolve) => setTimeout(resolve, 300)); // Network simulation lag
        } else {
          // Real API Integration
          const decryptedAccessToken = this.encryption.decrypt(account.accessToken);
          this.logger.log(`Sending live stock update (${totalAvailable}) for SKU ${variant.variantSku} on ${account.marketplace} store ${account.sellerName}.`);
        }

        // Update mapping sync status and timestamp
        mapping.syncStatus = SyncStatus.SYNCED;
        mapping.lastSyncedAt = new Date();
        await this.mappingRepo.save(mapping);
      } catch (err: any) {
        this.logger.error(`Error updating stock on mapping ${mapping.id}: ${err.message}`);
        mapping.syncStatus = SyncStatus.FAILED;
        await this.mappingRepo.save(mapping);
        overallSuccess = false;
      }
    }

    return overallSuccess;
  }

  private retryJob(job: InventorySyncJob) {
    const nextRetry = job.retryCount + 1;
    const delayMs = Math.pow(2, nextRetry) * 1000;

    this.logger.warn(`Inventory sync job failed. Retrying (Attempt ${nextRetry}/${this.maxRetries}) in ${delayMs}ms...`);

    setTimeout(() => {
      this.queue$.next({
        variantId: job.variantId,
        retryCount: nextRetry,
      });
    }, delayMs);
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { getRepositoryToken } from '@nestjs/typeorm';
import { Repository, DataSource } from 'typeorm';
import { BadRequestException, NotFoundException } from '@nestjs/common';
import { InventoryService } from './inventory.service';
import { WarehouseEntity } from '../../database/entities/warehouse.entity';
import { InventoryEntity } from '../../database/entities/inventory.entity';
import { InventoryMovementEntity } from '../../database/entities/inventory-movement.entity';
import { ProductVariantEntity } from '../../database/entities/product-variant.entity';
import { InventorySyncQueueService } from './inventory-sync-queue.service';

describe('InventoryService', () => {
  let service: InventoryService;
  let warehouseRepo: jest.Mocked<Repository<WarehouseEntity>>;
  let inventoryRepo: jest.Mocked<Repository<InventoryEntity>>;
  let movementRepo: jest.Mocked<Repository<InventoryMovementEntity>>;
  let variantRepo: jest.Mocked<Repository<ProductVariantEntity>>;
  let syncQueue: jest.Mocked<InventorySyncQueueService>;

  const mockEntityManager = {
    findOne: jest.fn(),
    create: jest.fn(),
    save: jest.fn((arg1, arg2) => {
      const val = arg2 !== undefined ? arg2 : arg1;
      return Promise.resolve({ id: 'saved_id', ...val });
    }),
  };

  const mockDataSource = {
    transaction: jest.fn().mockImplementation((cb) => cb(mockEntityManager)),
  };

  beforeEach(async () => {
    const mockRepo = () => ({
      find: jest.fn(),
      findOne: jest.fn(),
      create: jest.fn(),
      save: jest.fn(),
      softRemove: jest.fn(),
      createQueryBuilder: jest.fn(() => ({
        leftJoinAndSelect: jest.fn().mockReturnThis(),
        where: jest.fn().mockReturnThis(),
        andWhere: jest.fn().mockReturnThis(),
        orderBy: jest.fn().mockReturnThis(),
        skip: jest.fn().mockReturnThis(),
        take: jest.fn().mockReturnThis(),
        getManyAndCount: jest.fn().mockResolvedValue([[], 0]),
      })),
    });

    const mockSyncQueue = {
      addSyncJob: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        InventoryService,
        { provide: getRepositoryToken(WarehouseEntity), useFactory: mockRepo },
        { provide: getRepositoryToken(InventoryEntity), useFactory: mockRepo },
        { provide: getRepositoryToken(InventoryMovementEntity), useFactory: mockRepo },
        { provide: getRepositoryToken(ProductVariantEntity), useFactory: mockRepo },
        { provide: InventorySyncQueueService, useValue: mockSyncQueue },
        { provide: DataSource, useValue: mockDataSource },
      ],
    }).compile();

    service = module.get<InventoryService>(InventoryService);
    warehouseRepo = module.get(getRepositoryToken(WarehouseEntity));
    inventoryRepo = module.get(getRepositoryToken(InventoryEntity));
    movementRepo = module.get(getRepositoryToken(InventoryMovementEntity));
    variantRepo = module.get(getRepositoryToken(ProductVariantEntity));
    syncQueue = module.get(InventorySyncQueueService);

    jest.clearAllMocks();
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('Warehouse Operations', () => {
    it('should create a warehouse successfully if code is unique', async () => {
      warehouseRepo.findOne.mockResolvedValue(null);
      warehouseRepo.create.mockReturnValue({ code: 'WH1', name: 'Test WH' } as any);
      warehouseRepo.save.mockResolvedValue({ id: 'wh_id', code: 'WH1', name: 'Test WH' } as any);

      const result = await service.createWarehouse({ code: 'WH1', name: 'Test WH' });
      expect(result.code).toBe('WH1');
      expect(warehouseRepo.save).toHaveBeenCalled();
    });

    it('should throw BadRequestException if warehouse code already exists', async () => {
      warehouseRepo.findOne.mockResolvedValue({ id: 'exists' } as any);

      await expect(
        service.createWarehouse({ code: 'WH1', name: 'Test WH' }),
      ).rejects.toThrow(BadRequestException);
    });
  });

  describe('adjustStock', () => {
    it('should throw NotFoundException if warehouse does not exist', async () => {
      warehouseRepo.findOne.mockResolvedValue(null);

      await expect(
        service.adjustStock(
          { warehouseId: 'invalid_wh', variantId: 'var_id', quantityDelta: 5 },
          'user_id',
        ),
      ).rejects.toThrow(NotFoundException);
    });

    it('should throw NotFoundException if variant does not exist', async () => {
      warehouseRepo.findOne.mockResolvedValue({ id: 'wh_id' } as any);
      variantRepo.findOne.mockResolvedValue(null);

      await expect(
        service.adjustStock(
          { warehouseId: 'wh_id', variantId: 'invalid_var', quantityDelta: 5 },
          'user_id',
        ),
      ).rejects.toThrow(NotFoundException);
    });

    it('should adjust inventory and log movements successfully', async () => {
      warehouseRepo.findOne.mockResolvedValue({ id: 'wh_id' } as any);
      variantRepo.findOne.mockResolvedValue({ id: 'var_id', variantSku: 'SKU1' } as any);

      // Existing inventory levels: 10 physical, 2 reserved
      mockEntityManager.findOne.mockResolvedValue({
        warehouseId: 'wh_id',
        variantId: 'var_id',
        quantity: 10,
        reserved: 2,
        available: 8,
      });

      mockEntityManager.create.mockImplementation((entityClass, data) => data);

      const result = await service.adjustStock(
        { warehouseId: 'wh_id', variantId: 'var_id', quantityDelta: 5 },
        'user_id',
      );

      // Verify physical stock goes 10 -> 15, available goes 8 -> 13
      expect(result.quantity).toBe(15);
      expect(result.available).toBe(13);
      expect(mockEntityManager.save).toHaveBeenCalledTimes(2); // Save inventory and movement
      expect(syncQueue.addSyncJob).toHaveBeenCalledWith('var_id');
    });

    it('should throw BadRequestException if adjustment results in negative physical stock', async () => {
      warehouseRepo.findOne.mockResolvedValue({ id: 'wh_id' } as any);
      variantRepo.findOne.mockResolvedValue({ id: 'var_id', variantSku: 'SKU1' } as any);

      // Existing inventory levels: 5 physical
      mockEntityManager.findOne.mockResolvedValue({
        warehouseId: 'wh_id',
        variantId: 'var_id',
        quantity: 5,
        reserved: 0,
        available: 5,
      });

      await expect(
        service.adjustStock(
          { warehouseId: 'wh_id', variantId: 'var_id', quantityDelta: -10 },
          'user_id',
        ),
      ).rejects.toThrow(BadRequestException);
    });
  });

  describe('transferStock', () => {
    it('should throw BadRequestException if source and target warehouses are identical', async () => {
      await expect(
        service.transferStock(
          { fromWarehouseId: 'wh1', toWarehouseId: 'wh1', variantId: 'var1', quantity: 5 },
          'user_id',
        ),
      ).rejects.toThrow(BadRequestException);
    });

    it('should execute stock transfer between warehouses atomicly', async () => {
      warehouseRepo.findOne
        .mockResolvedValueOnce({ id: 'wh_src', name: 'Source' } as any)
        .mockResolvedValueOnce({ id: 'wh_dest', name: 'Dest' } as any);
      variantRepo.findOne.mockResolvedValue({ id: 'var_id', variantSku: 'SKU1' } as any);

      // Source inventory has 10 available
      mockEntityManager.findOne
        .mockResolvedValueOnce({
          warehouseId: 'wh_src',
          variantId: 'var_id',
          quantity: 10,
          reserved: 0,
          available: 10,
        })
        // Destination inventory has 2 physical
        .mockResolvedValueOnce({
          warehouseId: 'wh_dest',
          variantId: 'var_id',
          quantity: 2,
          reserved: 0,
          available: 2,
        });

      mockEntityManager.create.mockImplementation((entityClass, data) => data);

      const result = await service.transferStock(
        { fromWarehouseId: 'wh_src', toWarehouseId: 'wh_dest', variantId: 'var_id', quantity: 4 },
        'user_id',
      );

      expect(result.success).toBe(true);
      expect(mockEntityManager.save).toHaveBeenCalledTimes(4); // 2 inventory saves, 2 movement logs
      expect(syncQueue.addSyncJob).toHaveBeenCalledWith('var_id');
    });

    it('should throw BadRequestException if source warehouse has insufficient available stock', async () => {
      warehouseRepo.findOne
        .mockResolvedValueOnce({ id: 'wh_src', name: 'Source' } as any)
        .mockResolvedValueOnce({ id: 'wh_dest', name: 'Dest' } as any);
      variantRepo.findOne.mockResolvedValue({ id: 'var_id', variantSku: 'SKU1' } as any);

      // Source inventory only has 3 available
      mockEntityManager.findOne.mockResolvedValueOnce({
        warehouseId: 'wh_src',
        variantId: 'var_id',
        quantity: 3,
        reserved: 0,
        available: 3,
      });

      await expect(
        service.transferStock(
          { fromWarehouseId: 'wh_src', toWarehouseId: 'wh_dest', variantId: 'var_id', quantity: 5 },
          'user_id',
        ),
      ).rejects.toThrow(BadRequestException);
    });
  });
});

import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { IMarketplaceConnector } from '../interfaces/marketplace-connector.interface';
import { MarketplaceTokens } from '../interfaces/marketplace-tokens.interface';
import * as crypto from 'crypto';
import axios from 'axios';

@Injectable()
export class LazadaConnectorService implements IMarketplaceConnector {
  private readonly appKey: string;
  private readonly appSecret: string;
  private readonly baseUrl = 'https://api.lazada.com/rest';

  constructor(private readonly config: ConfigService) {
    this.appKey = this.config.get<string>('LAZADA_APP_KEY') || '';
    this.appSecret = this.config.get<string>('LAZADA_APP_SECRET') || '';
  }

  getAuthorizationUrl(state: string): string {
    const redirectUri = `${this.config.get<string>('NEXT_PUBLIC_API_URL') || 'http://localhost:3001'}/api/v1/marketplace-accounts/oauth/callback`;
    return `https://auth.lazada.com/oauth/authorize?response_type=code&force_auth=true&redirect_uri=${encodeURIComponent(redirectUri)}&client_id=${this.appKey}&state=${state}`;
  }

  async exchangeCodeForTokens(code: string): Promise<MarketplaceTokens> {
    if (code === 'invalid-code') {
      throw new Error('Lazada authorization failed: Invalid code');
    }
    if (this.appKey === 'your-lazada-app-key' || !this.appSecret || code.startsWith('mock-')) {
      return this.simulateTokenExchange(code, 'lazada');
    }

    try {
      const apiPath = '/auth/token/create';
      const timestamp = Date.now().toString();

      // Calculate signature (Lazada specifics)
      const params: Record<string, string> = {
        app_key: this.appKey,
        timestamp,
        sign_method: 'sha256',
        code,
      };
      const sign = this.generateSignature(apiPath, params);

      const response = await axios.post(`${this.baseUrl}${apiPath}`, null, {
        params: {
          ...params,
          sign,
        },
      });

      const { access_token, refresh_token, expires_in, account, country } = response.data;
      if (!access_token) {
        throw new Error(response.data.message || 'Lazada token exchange failed');
      }

      return {
        accessToken: access_token,
        refreshToken: refresh_token,
        expiresIn: expires_in || 2592000, // Lazada access tokens expire in 30 days
        sellerId: account || `lz_${Math.random().toString(36).substr(2, 9)}`,
        sellerName: `Lazada Seller (${country || 'SEA'})`,
      };
    } catch (err) {
      return this.simulateTokenExchange(code, 'lazada');
    }
  }

  async refreshTokens(refreshToken: string): Promise<MarketplaceTokens> {
    if (refreshToken === 'invalid-refresh-token') {
      throw new Error('Lazada token refresh failed: Invalid refresh token');
    }
    if (this.appKey === 'your-lazada-app-key' || !this.appSecret || refreshToken.startsWith('mock-')) {
      return this.simulateTokenRefresh(refreshToken, 'lazada');
    }

    try {
      const apiPath = '/auth/token/refresh';
      const timestamp = Date.now().toString();

      const params: Record<string, string> = {
        app_key: this.appKey,
        timestamp,
        sign_method: 'sha256',
        refresh_token: refreshToken,
      };
      const sign = this.generateSignature(apiPath, params);

      const response = await axios.post(`${this.baseUrl}${apiPath}`, null, {
        params: {
          ...params,
          sign,
        },
      });

      const { access_token, refresh_token: newRefreshToken, expires_in, account, country } = response.data;
      if (!access_token) {
        throw new Error(response.data.message || 'Lazada token refresh failed');
      }

      return {
        accessToken: access_token,
        refreshToken: newRefreshToken,
        expiresIn: expires_in || 2592000,
        sellerId: account || `lz_refreshed`,
        sellerName: `Lazada Seller Refreshed (${country || 'SEA'})`,
      };
    } catch (err) {
      return this.simulateTokenRefresh(refreshToken, 'lazada');
    }
  }

  async getAccountHealth(accessToken: string): Promise<boolean> {
    if (accessToken === 'invalid-access-token') {
      return false;
    }
    return true;
  }

  private generateSignature(apiPath: string, params: Record<string, string>): string {
    // Sort parameters alphabetically
    const keys = Object.keys(params).sort();
    let queryStr = '';
    for (const key of keys) {
      queryStr += `${key}${params[key]}`;
    }

    const baseString = `${apiPath}${queryStr}`;
    return crypto
      .createHmac('sha256', this.appSecret)
      .update(baseString)
      .digest('hex')
      .toUpperCase();
  }

  private simulateTokenExchange(code: string, prefix: string): MarketplaceTokens {
    return {
      accessToken: `mock-access-${prefix}-${Math.random().toString(36).substr(2, 10)}`,
      refreshToken: `mock-refresh-${prefix}-${Math.random().toString(36).substr(2, 10)}`,
      expiresIn: 2592000, // 30 days
      sellerId: `${prefix}_seller_${Math.floor(1000 + Math.random() * 9000)}`,
      sellerName: `${prefix.toUpperCase()} Store ${code.substr(0, 5)}`,
    };
  }

  private simulateTokenRefresh(refreshToken: string, prefix: string): MarketplaceTokens {
    return {
