    });
  });

  describe('getConnectedAccounts auto-expiration', () => {
    it('should automatically flag and update expired accounts in line', async () => {
      const expiredDate = new Date(Date.now() - 5000);
      const accountMock = {
        id: 'acc1',
        marketplace: MarketplaceType.TIKTOK,
        sellerId: 'seller1',
        accessToken: 'encrypted:token1',
        status: AccountStatus.ACTIVE,
        tokenExpiredAt: expiredDate,
      };
      accountRepo.find.mockResolvedValue([accountMock] as any);

      await service.getConnectedAccounts();

      expect(accountMock.status).toBe(AccountStatus.EXPIRED);
      expect(accountRepo.save).toHaveBeenCalledWith(accountMock);
    });
  });

  describe('handleDeauthorization', () => {
    it('should set disconnected and soft-delete store if match is found', async () => {
      const accountMock = {
        id: 'acc_deauth',
        marketplace: MarketplaceType.TIKTOK,
        sellerId: 'my_seller',
        status: AccountStatus.ACTIVE,
      };
      accountRepo.findOne.mockResolvedValue(accountMock as any);

      await service.handleDeauthorization('tiktok', 'my_seller');

      expect(accountMock.status).toBe(AccountStatus.DISCONNECTED);
      expect(accountRepo.save).toHaveBeenCalledWith(accountMock);
      expect(accountRepo.softDelete).toHaveBeenCalledWith('acc_deauth');
    });
  });
});

import {
  Injectable,
  BadRequestException,
  NotFoundException,
  OnModuleInit,
} from '@nestjs/common';
import { Subject } from 'rxjs';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, LessThan } from 'typeorm';
import * as crypto from 'crypto';
import {
  MarketplaceAccountEntity,
  MarketplaceType,
  AccountStatus,
} from '../../database/entities/marketplace-account.entity';
import { OAuthStateEntity } from '../../database/entities/oauth-state.entity';
import { EncryptionService } from './encryption.service';
import { MarketplaceConnectorResolver } from './marketplace-connector.resolver';

@Injectable()
export class MarketplaceService implements OnModuleInit {
  public readonly accountConnected$ = new Subject<string>();

  constructor(
    @InjectRepository(MarketplaceAccountEntity)
    private readonly accountRepo: Repository<MarketplaceAccountEntity>,
    @InjectRepository(OAuthStateEntity)
    private readonly stateRepo: Repository<OAuthStateEntity>,
    private readonly encryption: EncryptionService,
    private readonly connectorResolver: MarketplaceConnectorResolver,
  ) {}

  onModuleInit() {
    // Run automated token refresh check every 1 hour (3,600,000 milliseconds)
    setInterval(() => {
      this.autoRefreshTokens().catch((err) => {
        console.error('Automated token refresh check failed:', err);
      });
    }, 3600000);

    // Run automated token expiration check every 1 hour (3,600,000 milliseconds)
    setInterval(() => {
      this.checkTokenExpirations().catch((err) => {
        console.error('Automated token expiration check failed:', err);
      });
    }, 3600000);

    // Run automated health diagnostics check for all channels every 6 hours (21,600,000 milliseconds)
    setInterval(() => {
      this.checkAllAccountsHealth().catch((err) => {
        console.error('Automated system connection diagnostics check failed:', err);
      });
    }, 21600000);
  }

  /**
   * Generates a temporary state token and the redirection URL for OAuth connection.
   */
  async connect(marketplace: string, userId: string): Promise<{ url: string; state: string }> {
    const cleanMarketplace = marketplace.toLowerCase();
    if (
      cleanMarketplace !== MarketplaceType.TIKTOK &&
      cleanMarketplace !== MarketplaceType.SHOPEE &&
      cleanMarketplace !== MarketplaceType.LAZADA
    ) {
      throw new BadRequestException(`Unsupported marketplace: ${marketplace}`);
    }

    const stateToken = crypto.randomBytes(16).toString('hex');
    const expiration = new Date();
    expiration.setMinutes(expiration.getMinutes() + 10); // 10-minute expiration

    const oauthState = this.stateRepo.create({
      state: stateToken,
      marketplace: cleanMarketplace,
      expiredAt: expiration,
    });
    await this.stateRepo.save(oauthState);

    const connector = this.connectorResolver.resolve(cleanMarketplace);
    const url = connector.getAuthorizationUrl(stateToken);

    return { url, state: stateToken };
  }

  /**
   * Processes the callback from marketplace, exchanging the auth code for encrypted tokens.
   */
  async handleCallback(code: string, state: string, userId: string | null = null): Promise<any> {
    const stateRecord = await this.stateRepo.findOne({ where: { state } });
    if (!stateRecord) {
      throw new BadRequestException('OAuth validation failed: State not found');
    }

    if (new Date() > stateRecord.expiredAt) {
      await this.stateRepo.remove(stateRecord);
      throw new BadRequestException('OAuth validation failed: State has expired');
    }

    const marketplace = stateRecord.marketplace as MarketplaceType;
    const connector = this.connectorResolver.resolve(marketplace);

    // Exchange auth code for tokens
    const tokens = await connector.exchangeCodeForTokens(code);

    // Encrypt sensitive access and refresh tokens
    const encryptedAccessToken = this.encryption.encrypt(tokens.accessToken);
    const encryptedRefreshToken = this.encryption.encrypt(tokens.refreshToken);
    const tokenExpiredAt = new Date(Date.now() + tokens.expiresIn * 1000);

    // Check for existing account matching marketplace + sellerId
    let account = await this.accountRepo.findOne({
      where: { marketplace, sellerId: tokens.sellerId },
      withDeleted: true,
    });

    if (account) {
      // Re-enable and update existing account
      account.sellerName = tokens.sellerName;
      account.accessToken = encryptedAccessToken;
      account.refreshToken = encryptedRefreshToken;
      account.tokenExpiredAt = tokenExpiredAt;
      account.status = AccountStatus.ACTIVE;
      account.deletedAt = null;
      account.createdBy = userId || account.createdBy;
    } else {
      // Create new account
      account = this.accountRepo.create({
        marketplace,
        sellerId: tokens.sellerId,
        sellerName: tokens.sellerName,
        accessToken: encryptedAccessToken,
        refreshToken: encryptedRefreshToken,
        tokenExpiredAt,
        status: AccountStatus.ACTIVE,
        createdBy: userId,
      });
    }

    await this.accountRepo.save(account);

    // Trigger background sync events (historical sync for orders, products)
    this.accountConnected$.next(account.id);

    // Consume (delete) the temporary state
    await this.stateRepo.remove(stateRecord);

    return {
      id: account.id,
      marketplace: account.marketplace,
      sellerId: account.sellerId,
      sellerName: account.sellerName,
      status: account.status,
    };
  }

  /**
   * Retrieves all connected marketplace accounts. Omits sensitive token values for security.
   */
  async getConnectedAccounts(): Promise<any[]> {
    const accounts = await this.accountRepo.find();
    const now = new Date();
    let hasChanges = false;
    for (const acc of accounts) {
      if (acc.status === AccountStatus.ACTIVE && acc.tokenExpiredAt <= now) {
        acc.status = AccountStatus.EXPIRED;
        await this.accountRepo.save(acc);
        hasChanges = true;
      }
    }

    const finalAccounts = hasChanges ? await this.accountRepo.find() : accounts;
    return finalAccounts.map((acc) => {
      // Omit tokens to prevent exposing encrypted payloads to the client
      const { accessToken, refreshToken, ...publicFields } = acc;
      return publicFields;
    });
  }

  /**
   * Manually triggers token refresh for a specific account.
   */
  async refreshAccountTokens(id: string): Promise<any> {
    const account = await this.accountRepo.findOne({ where: { id } });
    if (!account) {
      throw new NotFoundException(`Marketplace account with ID ${id} not found`);
    }

    const decryptedRefreshToken = this.encryption.decrypt(account.refreshToken);
    const connector = this.connectorResolver.resolve(account.marketplace);

    const tokens = await connector.refreshTokens(decryptedRefreshToken);

    account.accessToken = this.encryption.encrypt(tokens.accessToken);
    account.refreshToken = this.encryption.encrypt(tokens.refreshToken);
    account.tokenExpiredAt = new Date(Date.now() + tokens.expiresIn * 1000);
    account.status = AccountStatus.ACTIVE;

    await this.accountRepo.save(account);

    const { accessToken, refreshToken, ...publicFields } = account;
    return publicFields;
  }

  /**
   * Disconnects and soft-deletes a marketplace account.
   */
  async disconnectAccount(id: string): Promise<void> {
    const account = await this.accountRepo.findOne({ where: { id } });
    if (!account) {
      throw new NotFoundException(`Marketplace account with ID ${id} not found`);
    }

    account.status = AccountStatus.DISCONNECTED;
    await this.accountRepo.save(account);
    await this.accountRepo.softDelete(id);
  }

  /**
   * Checks connection health using the connector interface.
   */
  async getAccountHealth(id: string): Promise<{ active: boolean }> {
    const account = await this.accountRepo.findOne({ where: { id } });
    if (!account) {
      throw new NotFoundException(`Marketplace account with ID ${id} not found`);
    }

    try {
      const decryptedAccessToken = this.encryption.decrypt(account.accessToken);
      const connector = this.connectorResolver.resolve(account.marketplace);

      const active = await connector.getAccountHealth(decryptedAccessToken);

      if (!active && account.status === AccountStatus.ACTIVE) {
        account.status = AccountStatus.EXPIRED;
        await this.accountRepo.save(account);
      } else if (active && account.status === AccountStatus.EXPIRED) {
        account.status = AccountStatus.ACTIVE;
        await this.accountRepo.save(account);
      }

      return { active };
    } catch (err) {
      return { active: false };
    }
  }

  /**
   * Handles deauthorization webhooks by updating the store connection status and soft-deleting.
   */
  async handleDeauthorization(marketplace: string, sellerId: string): Promise<void> {
    const cleanMarketplace = marketplace.toLowerCase() as MarketplaceType;
    const account = await this.accountRepo.findOne({
      where: { marketplace: cleanMarketplace, sellerId },
    });

    if (account) {
      account.status = AccountStatus.DISCONNECTED;
      await this.accountRepo.save(account);
      await this.accountRepo.softDelete(account.id);
    }
  }

  /**
   * Automatically refreshes all active accounts' tokens that are expiring within the next 24 hours.
   */
  async autoRefreshTokens(): Promise<void> {
    const thresholdDate = new Date();
    thresholdDate.setHours(thresholdDate.getHours() + 24);

    const expiringAccounts = await this.accountRepo.find({
      where: {
        status: AccountStatus.ACTIVE,
        tokenExpiredAt: LessThan(thresholdDate),
      },
    });

    for (const account of expiringAccounts) {
      try {
        await this.refreshAccountTokens(account.id);
      } catch (err) {
        console.error(`Failed to automatically refresh token for account ${account.id}:`, err);
      }
    }
  }

  /**
   * Scans and flags expired accounts in the database.
   */
  async checkTokenExpirations(): Promise<{ updatedCount: number }> {
    const now = new Date();
    const activeAccounts = await this.accountRepo.find({
      where: { status: AccountStatus.ACTIVE },
    });

    let updatedCount = 0;
    for (const account of activeAccounts) {
      if (account.tokenExpiredAt <= now) {
        account.status = AccountStatus.EXPIRED;
        await this.accountRepo.save(account);
        updatedCount++;
      }
    }
    return { updatedCount };
  }

  /**
   * Iterates through active/expired marketplace channels and executes connector health verification.
   */
  async checkAllAccountsHealth(): Promise<{ checkedCount: number; unhealthyCount: number }> {
    const accounts = await this.accountRepo.find();
    const activeOrExpired = accounts.filter(
      (acc) => acc.status === AccountStatus.ACTIVE || acc.status === AccountStatus.EXPIRED,
    );

    let unhealthyCount = 0;
    for (const account of activeOrExpired) {
      try {
        const { active } = await this.getAccountHealth(account.id);
        if (!active) {
          unhealthyCount++;
        }
      } catch (err) {
        unhealthyCount++;
      }
    }

    return {
      checkedCount: activeOrExpired.length,
      unhealthyCount,
    };
  }
}

import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, MoreThanOrEqual } from 'typeorm';
import { OrderEntity } from '../../database/entities/order.entity';
import { SyncJobEntity, SyncJobStatus } from '../../database/entities/sync-job.entity';
import { FailedJobEntity, FailedJobStatus } from '../../database/entities/failed-job.entity';
import { OrderSyncFailureEntity, SyncFailureStatus } from '../../database/entities/order-sync-failure.entity';
import { MarketplaceAccountEntity, AccountStatus } from '../../database/entities/marketplace-account.entity';
import { WebhookEventEntity, WebhookEventStatus } from '../../database/entities/webhook-event.entity';
import { WebhookDeliveryLogEntity } from '../../database/entities/webhook-delivery-log.entity';

export interface DashboardMetrics {
  orders: {
    totalToday: number;
    totalAll: number;
  };
  syncJobs: {
    pending: number;
    active: number;
    completed: number;
    failed: number;
    dead: number;
  };
  webhooks: {
    totalToday: number;
    processed: number;
    failed: number;
  };
  marketplace: {
    activeAccounts: number;
    totalAccounts: number;
    expiredAccounts: number;
  };
  failedOrders: {
    total: number;
    pending: number;
  };
}

export interface SyncStats {
  summary: {
    totalJobs: number;
    completedJobs: number;
    failedJobs: number;
    deadJobs: number;
    successRate: string;
  };
  last24h: {
    completed: number;
    failed: number;
    avgProcessingMs: number | null;
  };
  byMarketplace: Array<{
    marketplace: string;
    total: number;
    completed: number;
    failed: number;
    successRate: string;
  }>;
  recentJobs: SyncJobEntity[];
}

export interface MarketplaceStats {
  accounts: Array<{
    id: string;
    marketplace: string;
    sellerName: string;
    status: string;
    tokenExpiredAt: Date;
    orderCount: number;
    failedSyncs: number;
    lastSyncAt: Date | null;
  }>;
}

export interface WebhookStats {
  byStatus: {
    received: number;
    processing: number;
    processed: number;
    failed: number;
    ignored: number;
  };
  last1h: {
    received: number;
    failed: number;
    ignored: number;
  };
  recentDeliveryLogs: Array<{
    id: string;
    webhookEventId: string;
    action: string;
    status: string;
    detail: string;
    processingTimeMs: number;
    createdAt: Date;
  }>;
  recentEvents: WebhookEventEntity[];
}

/**
 * MonitoringService
 *
 * Aggregates cross-domain statistics from OrderEntity, SyncJobEntity,
 * FailedJobEntity, WebhookEventEntity, MarketplaceAccountEntity and more
 * to power the real-time Monitoring Dashboard.
 */
@Injectable()
export class MonitoringService {
  constructor(
    @InjectRepository(OrderEntity)
    private readonly orderRepo: Repository<OrderEntity>,
    @InjectRepository(SyncJobEntity)
    private readonly syncJobRepo: Repository<SyncJobEntity>,
    @InjectRepository(FailedJobEntity)
    private readonly failedJobRepo: Repository<FailedJobEntity>,
    @InjectRepository(OrderSyncFailureEntity)
    private readonly failureRepo: Repository<OrderSyncFailureEntity>,
    @InjectRepository(MarketplaceAccountEntity)
    private readonly accountRepo: Repository<MarketplaceAccountEntity>,
    @InjectRepository(WebhookEventEntity)
    private readonly webhookEventRepo: Repository<WebhookEventEntity>,
    @InjectRepository(WebhookDeliveryLogEntity)
    private readonly deliveryLogRepo: Repository<WebhookDeliveryLogEntity>,
  ) {}

  /**
   * Aggregated KPI metrics for the Overview / Dashboard page.
   */
  async getDashboardMetrics(): Promise<DashboardMetrics> {
    const todayStart = new Date();
    todayStart.setHours(0, 0, 0, 0);

    const [
      totalOrdersToday,
      totalOrdersAll,
      pendingJobs,
      activeJobs,
      completedJobs,
      failedJobs,
      deadJobs,
      webhookToday,
      webhookProcessed,
      webhookFailed,
      activeAccounts,
      totalAccounts,
      expiredAccounts,
      failedOrderTotal,
      failedOrderPending,
    ] = await Promise.all([
      this.orderRepo.count({ where: { createdAt: MoreThanOrEqual(todayStart) } }),
      this.orderRepo.count(),
      this.syncJobRepo.count({ where: { status: SyncJobStatus.PENDING } }),
      this.syncJobRepo.count({ where: { status: SyncJobStatus.ACTIVE } }),
      this.syncJobRepo.count({ where: { status: SyncJobStatus.COMPLETED } }),
      this.syncJobRepo.count({ where: { status: SyncJobStatus.FAILED } }),
      this.failedJobRepo.count({ where: { status: FailedJobStatus.DEAD } }),
      this.webhookEventRepo.count({ where: { createdAt: MoreThanOrEqual(todayStart) } }),
      this.webhookEventRepo.count({ where: { status: WebhookEventStatus.PROCESSED } }),
      this.webhookEventRepo.count({ where: { status: WebhookEventStatus.FAILED } }),
      this.accountRepo.count({ where: { status: AccountStatus.ACTIVE } }),
      this.accountRepo.count(),
      this.accountRepo.count({ where: { status: AccountStatus.EXPIRED } }),
      this.failureRepo.count(),
      this.failureRepo.count({ where: { status: SyncFailureStatus.FAILED } }),
    ]);

    return {
      orders: { totalToday: totalOrdersToday, totalAll: totalOrdersAll },
      syncJobs: { pending: pendingJobs, active: activeJobs, completed: completedJobs, failed: failedJobs, dead: deadJobs },
      webhooks: { totalToday: webhookToday, processed: webhookProcessed, failed: webhookFailed },
      marketplace: { activeAccounts, totalAccounts, expiredAccounts },
      failedOrders: { total: failedOrderTotal, pending: failedOrderPending },
    };
  }

  /**
   * Sync job statistics — summary, last-24h throughput, per-marketplace breakdown.
   */
  async getSyncStats(): Promise<SyncStats> {
    const since24h = new Date(Date.now() - 24 * 60 * 60 * 1000);

    const [totalJobs, completedJobs, failedJobs, deadJobs] = await Promise.all([
      this.syncJobRepo.count(),
      this.syncJobRepo.count({ where: { status: SyncJobStatus.COMPLETED } }),
      this.syncJobRepo.count({ where: { status: SyncJobStatus.FAILED } }),
      this.failedJobRepo.count({ where: { status: FailedJobStatus.DEAD } }),
    ]);

    const successRate =
      totalJobs > 0 ? ((completedJobs / totalJobs) * 100).toFixed(1) + '%' : 'N/A';

    // Last-24h stats
    const [completed24h, failed24h] = await Promise.all([
      this.syncJobRepo.count({
        where: { status: SyncJobStatus.COMPLETED, createdAt: MoreThanOrEqual(since24h) },
      }),
      this.syncJobRepo.count({
        where: { status: SyncJobStatus.FAILED, createdAt: MoreThanOrEqual(since24h) },
      }),
    ]);

    // Average processing time for completed jobs
    const avgResult = await this.syncJobRepo
      .createQueryBuilder('sj')
      .select('AVG(sj.processingTimeMs)', 'avg')
      .where('sj.status = :status', { status: SyncJobStatus.COMPLETED })
      .andWhere('sj.processingTimeMs IS NOT NULL')
      .getRawOne<{ avg: string | null }>();

    const avgProcessingMs = avgResult?.avg ? Math.round(Number(avgResult.avg)) : null;

    // Per-marketplace breakdown
    const marketplaceRaw = await this.syncJobRepo
      .createQueryBuilder('sj')
      .select('sj.marketplace', 'marketplace')
      .addSelect('COUNT(*)', 'total')
      .addSelect(`SUM(CASE WHEN sj.status = '${SyncJobStatus.COMPLETED}' THEN 1 ELSE 0 END)`, 'completed')
      .addSelect(`SUM(CASE WHEN sj.status = '${SyncJobStatus.FAILED}' THEN 1 ELSE 0 END)`, 'failed')
      .where('sj.marketplace IS NOT NULL')
      .groupBy('sj.marketplace')
      .getRawMany<{ marketplace: string; total: string; completed: string; failed: string }>();

    const byMarketplace = marketplaceRaw.map((r) => {
      const total = Number(r.total);
      const completed = Number(r.completed);
      return {
        marketplace: r.marketplace,
        total,
        completed,
        failed: Number(r.failed),
        successRate: total > 0 ? ((completed / total) * 100).toFixed(1) + '%' : 'N/A',
      };
    });

    // Recent 20 sync jobs
    const recentJobs = await this.syncJobRepo.find({
      order: { createdAt: 'DESC' },
      take: 20,
    });

    return {
      summary: { totalJobs, completedJobs, failedJobs, deadJobs, successRate },
      last24h: { completed: completed24h, failed: failed24h, avgProcessingMs },
      byMarketplace,
      recentJobs,
    };
  }

  /**
   * Per-marketplace statistics — order count, failed syncs, last sync timestamp.
   */
  async getMarketplaceStats(): Promise<MarketplaceStats> {
    const accounts = await this.accountRepo.find({ order: { createdAt: 'DESC' } });

    const results = await Promise.all(
      accounts.map(async (acc) => {
        const [orderCount, failedSyncs] = await Promise.all([
          this.orderRepo.count({ where: { marketplaceAccountId: acc.id } }),
          this.failureRepo.count({ where: { marketplaceAccountId: acc.id } }),
        ]);

        // Find the most recent completed sync job for this account
        const lastJob = await this.syncJobRepo.findOne({
          where: { marketplaceAccountId: acc.id, status: SyncJobStatus.COMPLETED },
          order: { completedAt: 'DESC' },
        });

        const { accessToken, refreshToken, ...publicFields } = acc as any;
        return {
          ...publicFields,
          orderCount,
          failedSyncs,
          lastSyncAt: lastJob?.completedAt ?? null,
        };
      }),
    );

    return { accounts: results };
  }

  /**
   * Webhook event statistics — status distribution, last-1h counts, recent delivery logs.
   */
  async getWebhookStats(): Promise<WebhookStats> {
    const since1h = new Date(Date.now() - 60 * 60 * 1000);

    const [received, processing, processed, failed, ignored] = await Promise.all([
      this.webhookEventRepo.count({ where: { status: WebhookEventStatus.RECEIVED } }),
      this.webhookEventRepo.count({ where: { status: WebhookEventStatus.PROCESSING } }),
      this.webhookEventRepo.count({ where: { status: WebhookEventStatus.PROCESSED } }),
      this.webhookEventRepo.count({ where: { status: WebhookEventStatus.FAILED } }),
      this.webhookEventRepo.count({ where: { status: WebhookEventStatus.IGNORED } }),
    ]);

    const [received1h, failed1h, ignored1h] = await Promise.all([
      this.webhookEventRepo.count({ where: { createdAt: MoreThanOrEqual(since1h) } }),
      this.webhookEventRepo.count({
        where: { status: WebhookEventStatus.FAILED, createdAt: MoreThanOrEqual(since1h) },
      }),
      this.webhookEventRepo.count({
        where: { status: WebhookEventStatus.IGNORED, createdAt: MoreThanOrEqual(since1h) },
      }),
    ]);

    const recentDeliveryLogs = await this.deliveryLogRepo.find({
      order: { createdAt: 'DESC' },
      take: 15,
    });

    const recentEvents = await this.webhookEventRepo.find({
      order: { createdAt: 'DESC' },
      take: 20,
    });

    return {
      byStatus: { received, processing, processed, failed, ignored },
      last1h: { received: received1h, failed: failed1h, ignored: ignored1h },
      recentDeliveryLogs: recentDeliveryLogs.map((l) => ({
        id: l.id,
        webhookEventId: l.webhookEventId,
        action: l.action,
        status: l.status,
        detail: l.detail,
        processingTimeMs: l.processingTimeMs,
        createdAt: l.createdAt,
      })),
      recentEvents,
    };
  }
}

